                      CREATE View [SSRS].[League_Divisions_STD]  as    Select  League_ID,    Name,   Division_of_fixture,    Year_of_Fixture,    Sum([No Result])[No Result],     Sum(Abandoned  )Abandoned  ,   Sum(Cancelled  )Cancelled  ,   Sum(Conceded   )Conceded   ,   Sum(InProgress )InProgress ,   Sum(Win     )Win     ,   Sum(ShortSided )ShortSided        FROM SSRS.Leagues_Division_STD_2026  where MONTHofFixture <= DatePart(Month,Getdate())-1  Group by League_ID,    Name,    Division_Of_Fixture,    Year_of_Fixture        